// Time:  O(n)
// Space: O(n)

class Solution {
public:
    string pushDominoes(string dominoes) {
        vector<int> force(dominoes.length());

        int f = 0;
        for (int i = 0; i < dominoes.length(); ++i) {
            if (dominoes[i] == 'R') {
                f = dominoes.length();
            } else if (dominoes[i] == 'L') {
                f = 0;
            } else {
                f = max(f - 1, 0);
            }
            force[i] += f;
        }

        f = 0;
        for (int i = dominoes.length() - 1; i >= 0; --i) {
            if (dominoes[i] == 'L') {
                f = dominoes.length();
            } else if (dominoes[i] == 'R') {
                f = 0;
            } else {
                f = max(f - 1, 0);
            }
            force[i] -= f;
        }
        string result;
        for (const auto& f : force) {
            result.push_back((f == 0) ? '.' : ((f > 0) ? 'R' : 'L'));
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(n)


class Solution(object):
    def pushDominoes(self, dominoes):
        """
        :type dominoes: str
        :rtype: str
        """
        force = [0]*len(dominoes)

        f = 0
        for i in xrange(len(dominoes)):
            if dominoes[i] == 'R':
                f = len(dominoes)
            elif dominoes[i] == 'L':
                f = 0
            else:
                f = max(f-1, 0)
            force[i] += f

        f = 0
        for i in reversed(xrange(len(dominoes))):
            if dominoes[i] == 'L':
                f = len(dominoes)
            elif dominoes[i] == 'R':
                f = 0
            else:
                f = max(f-1, 0)
            force[i] -= f

        return "".join('.' if f == 0 else 'R' if f > 0 else 'L'
                       for f in force)
